-- ============================================================
-- 6. forecasting.demand_forecasts  (20 SKUs × 3 DCs × 3 horizons = 180 rows for latest run)
-- Uses a cross-join across SKU/DC/horizon value lists.
-- ============================================================

INSERT INTO forecasting.demand_forecasts
  (run_id, sku_id, dc_id, forecast_date, horizon_days, p10, p50, p90)
SELECT
  '55555555-0030-0000-0000-000000000001',
  s.sku_id,
  d.dc_id,
  CURRENT_DATE + (h.horizon_days || ' days')::interval,
  h.horizon_days,
  (h.base_p10 + dc_offset.offset_val)::int,
  (h.base_p50 + dc_offset.offset_val)::int,
  (h.base_p90 + dc_offset.offset_val)::int
FROM
  (VALUES
    ('SKU-BEV-001'), ('SKU-BEV-002'), ('SKU-BEV-003'), ('SKU-BEV-004'), ('SKU-BEV-005'),
    ('SKU-SNK-001'), ('SKU-SNK-002'), ('SKU-SNK-003'), ('SKU-SNK-004'), ('SKU-SNK-005'),
    ('SKU-DRY-001'), ('SKU-DRY-002'), ('SKU-DRY-003'), ('SKU-DRY-004'), ('SKU-DRY-005'),
    ('SKU-CHL-001'), ('SKU-CHL-002'), ('SKU-CHL-003'), ('SKU-CHL-004'), ('SKU-CHL-005')
  ) AS s(sku_id),
  (VALUES ('DC-LONDON'), ('DC-MANCHESTER'), ('DC-BIRMINGHAM')) AS d(dc_id),
  (VALUES (7, 80, 120, 165), (14, 150, 220, 300), (30, 310, 450, 610)) AS h(horizon_days, base_p10, base_p50, base_p90),
  (VALUES ('DC-LONDON', 10), ('DC-MANCHESTER', 0), ('DC-BIRMINGHAM', -5)) AS dc_offset(dc_name, offset_val)
WHERE d.dc_id = dc_offset.dc_name
ON CONFLICT (run_id, sku_id, dc_id, forecast_date, horizon_days) DO NOTHING;

